+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * Transport function signature — abstracts the actual HTTP POST delivery.
+ * Return true for success, or throw/return false for failure.
+ */
+export type WebhookTransport = (url: string, body: WebhookBody) => Promise<boolean>;
+
+/**
+ * The JSON body posted to the webhook URL.
+ */
+export interface WebhookBody {
+  type: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  metadata?: Record<string, string>;
+  timestamp: string;
+}
+
+/**
+ * Configuration for the WebhookAdapter.
+ */
+export interface WebhookAdapterConfig {
+  /** The webhook endpoint URL to POST notifications to. */
+  url: string;
+  /** Optional custom transport. Defaults to logging transport. */
+  transport?: WebhookTransport;
+}
+
+const WEBHOOK_URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/;
+
+/**
+ * Validate that a URL string is a plausible HTTP(S) URL.
+ */
+export function isValidWebhookUrl(url: string): boolean {
+  return WEBHOOK_URL_REGEX.test(url);
+}
+
+export class WebhookAdapter implements NotificationAdapter {
+  readonly channel = 'webhook' as const;
+  private logger = new Logger('WebhookAdapter');
+  private readonly url: string;
+  private readonly transport: WebhookTransport;
+  /** Sent payloads — accessible for testing. */
+  readonly sentPayloads: WebhookBody[] = [];
+
+  constructor(config: WebhookAdapterConfig) {
+    this.url = config.url;
+    this.transport = config.transport ?? this.defaultTransport.bind(this);
+  }
+
+  /**
+   * Format a notification payload into the webhook JSON body.
+   */
+  formatPayload(payload: NotificationPayload): WebhookBody {
+    return {
+      type: payload.type,
+      recipient: payload.recipient,
+      subject: payload.subject,
+      body: payload.body,
+      metadata: payload.metadata,
+      timestamp: new Date().toISOString(),
+    };
+  }
+
+  /**
+   * Send a notification via HTTP POST to the configured webhook URL.
+   *
+   * 1. Validates the configured URL.
+   * 2. Formats the payload as JSON.
+   * 3. Posts via the configured transport.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    if (!isValidWebhookUrl(this.url)) {
+      this.logger.warn(`Invalid webhook URL: ${this.url}`);
+      return { success: false, error: `Invalid webhook URL: ${this.url}` };
+    }
+
+    const webhookBody = this.formatPayload(payload);
+
+    try {
+      const delivered = await this.transport(this.url, webhookBody);
+      if (delivered) {
+        this.sentPayloads.push(webhookBody);
+        this.logger.info(`Webhook delivered to ${this.url}: ${payload.subject}`);
+        return { success: true };
+      }
+      this.logger.error(`Transport returned failure for ${this.url}`);
+      return { success: false, error: 'Webhook delivery failed' };
