+   * Default transport — logs the webhook and returns success.
+   * Replaced with a real transport in production.
+   */
+  private async defaultTransport(url: string, body: WebhookBody): Promise<boolean> {
+    this.logger.info(`[DefaultTransport] POST ${url}: ${JSON.stringify(body)}`);
+    return true;
+  }
+}

