/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements a pluggable transport layer for posting JSON payloads to
 * webhook URLs. The default transport logs sends; inject a real
 * transport (fetch, axios) for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Transport function signature — abstracts the actual HTTP POST delivery.
 * Return true for success, or throw/return false for failure.
 */
export type WebhookTransport = (url: string, body: WebhookBody) => Promise<boolean>;

/**
 * The JSON body posted to the webhook URL.
 */
export interface WebhookBody {
  type: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, string>;
  timestamp: string;
}

/**
 * Configuration for the WebhookAdapter.
 */
export interface WebhookAdapterConfig {
  /** The webhook endpoint URL to POST notifications to. */
  url: string;
  /** Optional custom transport. Defaults to logging transport. */
  transport?: WebhookTransport;
}

/**
 * Validate that a URL string is a plausible HTTP(S) URL.
 */
export function isValidWebhookUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private readonly url: string;
  private readonly transport: WebhookTransport;
  /** Sent payloads — accessible for testing. */
  readonly sentPayloads: WebhookBody[] = [];

  constructor(config: WebhookAdapterConfig) {
    this.url = config.url;
    this.transport = config.transport ?? this.defaultTransport.bind(this);
  }

  /**
   * Format a notification payload into the webhook JSON body.
   */
  formatPayload(payload: NotificationPayload): WebhookBody {
    return {
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Send a notification via HTTP POST to the configured webhook URL.
   *
   * 1. Validates the configured URL.
   * 2. Formats the payload as JSON.
   * 3. Posts via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidWebhookUrl(this.url)) {
      this.logger.warn(`Invalid webhook URL: ${this.url}`);
      return { success: false, error: `Invalid webhook URL: ${this.url}` };
    }

    const webhookBody = this.formatPayload(payload);

    try {
      const delivered = await this.transport(this.url, webhookBody);
      if (delivered) {
        this.sentPayloads.push(webhookBody);
        this.logger.info(`Webhook delivered to ${this.url}: ${payload.subject}`);
        return { success: true };
      }
      this.logger.error(`Transport returned failure for ${this.url}`);
      return { success: false, error: 'Webhook delivery failed' };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Transport error for ${this.url}: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }
  }

  /**
   * Default transport — logs the webhook and returns success.
   * Replaced with a real transport in production.
   */
  private async defaultTransport(url: string, body: WebhookBody): Promise<boolean> {
    this.logger.info(`[DefaultTransport] POST ${url}: ${JSON.stringify(body)}`);
    return true;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter, isValidWebhookUrl } from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport, WebhookBody } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: 'user-123',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'webhook',
    metadata: { userId: 'user-123', items: 'Widget x2' },
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let delivered: { url: string; body: WebhookBody }[];
  let transport: WebhookTransport;

  beforeEach(() => {
    delivered = [];
    transport = async (url, body) => {
      delivered.push({ url, body });
      return true;
    };
    adapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify', transport });
  });

  describe('send', () => {
    it('should deliver webhook through the transport', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(delivered).toHaveLength(1);
      expect(delivered[0]?.url).toBe('https://hooks.example.com/notify');
      expect(delivered[0]?.body.type).toBe('order_confirmation');
      expect(delivered[0]?.body.recipient).toBe('user-123');
      expect(delivered[0]?.body.subject).toBe('Order Confirmation: order-1');
    });

    it('should track sent payloads', async () => {
      await adapter.send(makePayload());
      expect(adapter.sentPayloads).toHaveLength(1);
      expect(adapter.sentPayloads[0]?.type).toBe('order_confirmation');
    });

    it('should return failure for invalid URL', async () => {
      const badAdapter = new WebhookAdapter({ url: 'not-a-url', transport });

      const result = await badAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(delivered).toHaveLength(0);
    });

    it('should return failure when transport returns false', async () => {
      const failTransport: WebhookTransport = async () => false;
      const failAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        transport: failTransport,
      });

      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Webhook delivery failed');
    });

    it('should catch transport errors and return failure', async () => {
      const errorTransport: WebhookTransport = async () => {
        throw new Error('Connection refused');
      };
      const errorAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        transport: errorTransport,
      });

      const result = await errorAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as webhook body', () => {
      const body = adapter.formatPayload(makePayload());

      expect(body.type).toBe('order_confirmation');
      expect(body.recipient).toBe('user-123');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toContain('Your order has been placed');
      expect(body.metadata).toEqual({ userId: 'user-123', items: 'Widget x2' });
      expect(body.timestamp).toBeDefined();
    });

    it('should include ISO timestamp', () => {
      const body = adapter.formatPayload(makePayload());
      expect(() => new Date(body.timestamp)).not.toThrow();
      expect(new Date(body.timestamp).toISOString()).toBe(body.timestamp);
    });

    it('should handle payload without metadata', () => {
      const body = adapter.formatPayload(makePayload({ metadata: undefined }));
      expect(body.metadata).toBeUndefined();
    });
  });

  describe('all notification types', () => {
    it('should format order_status_update', async () => {
      await adapter.send(
        makePayload({
          type: 'order_status_update',
          subject: 'Order Update: order-1',
          body: 'Status changed from pending to confirmed.',
        }),
      );

      expect(delivered[0]?.body.type).toBe('order_status_update');
      expect(delivered[0]?.body.body).toContain('pending to confirmed');
    });

    it('should format welcome notification', async () => {
      await adapter.send(
        makePayload({
          type: 'welcome',
          subject: 'Welcome!',
          body: 'Welcome to the platform.',
        }),
      );

      expect(delivered[0]?.body.type).toBe('welcome');
    });

    it('should format account_update notification', async () => {
      await adapter.send(
        makePayload({
          type: 'account_update',
          subject: 'Account Updated',
          body: 'Your email has been changed.',
        }),
      );

      expect(delivered[0]?.body.type).toBe('account_update');
    });
  });

  describe('isValidWebhookUrl', () => {
    it('should accept valid HTTP URLs', () => {
      expect(isValidWebhookUrl('http://example.com/webhook')).toBe(true);
      expect(isValidWebhookUrl('https://hooks.example.com/notify')).toBe(true);
      expect(isValidWebhookUrl('https://example.com:8080/path')).toBe(true);
    });

    it('should reject invalid URLs', () => {
      expect(isValidWebhookUrl('')).toBe(false);
      expect(isValidWebhookUrl('not-a-url')).toBe(false);
      expect(isValidWebhookUrl('ftp://example.com/hook')).toBe(false);
      expect(isValidWebhookUrl('javascript:alert(1)')).toBe(false);
    });
  });

  describe('default transport', () => {
    it('should use default logging transport when none provided', async () => {
      const defaultAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
      const result = await defaultAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(defaultAdapter.sentPayloads).toHaveLength(1);
    });
  });

  describe('channel property', () => {
    it('should expose webhook channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });
});

